const o=()=>({initReveal:()=>{if(typeof window>"u")return;const t=new IntersectionObserver(r=>{r.forEach(s=>{if(s.isIntersecting){const e=s.target,n=e.dataset.delay?parseInt(e.dataset.delay):0;setTimeout(()=>{e.classList.add("is-visible")},n),t.unobserve(e)}})},{threshold:.1,rootMargin:"0px 0px -50px 0px"});return document.querySelectorAll(".reveal, .reveal-left, .reveal-right, .reveal-scale").forEach(r=>t.observe(r)),()=>t.disconnect()}});export{o as u};
